66	    while (lex_pos < lex_len) {
67	        int c = lex_peek();
68	
69	        if (is_space(c)) {
70	            lex_advance();
71	            continue;
72	        }
73	
74	        /* block comment: / * ... * / */
75	        if (c == 47 && lex_peek2() == 42) {
76	            lex_advance();
77	            lex_advance();
