3	#ifndef IO_H
4	#define IO_H
5	
6	/* ---- UART hardware ---- */
7	
8	#define UART_DATA   0xFF0100
9	#define UART_STATUS 0xFF0101
10	
11	void uart_putchar(int ch) {
12	    while (*(char *)UART_STATUS & 0x80) {}
13	    *(char *)UART_DATA = ch;
14	}
15	
16	int uart_getchar(void) {
17	    while (!(*(char *)UART_STATUS & 0x01)) {}
18	    return *(char *)UART_DATA;
19	}
20	
21	void uart_puts(char *s) {
22	    while (*s) {
23	        uart_putchar(*s);
24	        s = s + 1;
25	    }
26	    uart_putchar(10);
27	}
28	
29	void uart_putstr(char *s) {
30	    while (*s) {
31	        uart_putchar(*s);
32	        s = s + 1;
33	    }
34	}
35	
36	/* Read a line with backspace/DEL support. Returns length. */
37	int uart_getline(char *buf, int len) {
38	    int pos = 0;
39	    int maxpos = len - 1;
40	
41	    while (1) {
42	        int ch = uart_getchar();
43	
44	        if (ch == 10 || ch == 13) {
45	            uart_putchar(10);
46	            buf[pos] = 0;
47	            return pos;
48	        }
49	
50	        if (ch == 8 || ch == 127) {
51	            if (pos > 0) {
52	                pos--;
53	                uart_putchar(8);
54	                uart_putchar(32);
55	                uart_putchar(8);
56	            }
57	        } else if (ch >= 32 && pos < maxpos) {
58	            buf[pos] = ch;
59	            pos++;
60	            uart_putchar(ch);
61	        }
62	    }
63	}
64	
65	/* ---- Numeric I/O ---- */
66	
67	void print_int(int n) {
68	    if (n < 0) {
69	        uart_putchar(45);  /* '-' */
70	        n = 0 - n;
71	    }
72	    if (n == 0) {
73	        uart_putchar(48);
74	        return;
75	    }
76	    char buf[8];
77	    int i = 0;
78	    while (n > 0) {
79	        buf[i] = 48 + n % 10;
80	        n = n / 10;
81	        i++;
82	    }
83	    while (i > 0) {
84	        i--;
85	        uart_putchar(buf[i]);
86	    }
87	}
88	
89	/* Parse decimal integer from string. Returns value, sets *end to
90	   index past last digit consumed. Returns 0 with *end == start
91	   if no digits found. */
92	int parse_int(char *s, int start, int *end) {
93	    int i = start;
94	    int neg = 0;
95	    int val = 0;
96	    int got = 0;
97	
98	    if (s[i] == 45) {  /* '-' */
99	        neg = 1;
100	        i++;
101	    }
102	
103	    while (s[i] >= 48 && s[i] <= 57) {
104	        val = val * 10 + (s[i] - 48);
105	        i++;
106	        got = 1;
107	    }
108	
109	    if (got == 0) {
110	        *end = start;
111	        return 0;
112	    }
113	
114	    *end = i;
115	    if (neg) {
116	        return 0 - val;
117	    }
118	    return val;
119	}
