        uart_putstr(" width=");
        print_int(sym_width[idx]);
        uart_putchar(10);

        layout_print_frame();
    } else {
        uart_puts("  PARSE ERROR");
    }

    /* Test 8: mixed param types (BYTE, PTR, INT24) */
    uart_puts("--- mixed params ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
