    /* Test 4: Assign to BYTE variable (1-byte store) */
    uart_puts("--- asgn: byte var ---");
    arena_init();
    ast_init();
    sym_init();
    emit_init();
    cg_init();
    si = sym_insert("B", TYPE_BYTE, 1, STOR_AUTO);
    sym_offset[si] = -1;
