    sym_offset[si] = -6;
    si = sym_insert("Z", TYPE_INT24, 3, STOR_AUTO);
    sym_offset[si] = -9;
    /* X = 10 */
    cg_assign(nd_assign(nd_ident("X"), nd_literal(10)));
