        }
        if (!str_find(out, "sw      r0,0(sp)")) {
            uart_puts("  FAIL: missing arg store");
            errs = errs + 1;
        }
        if (!str_find(out, "la      r2,_PRINT")) {
            uart_puts("  FAIL: missing call target");
            errs = errs + 1;
        }
        if (!str_find(out, "add     sp,r2")) {
            uart_puts("  FAIL: missing stack cleanup");
            errs = errs + 1;
        }
