        if (!str_find(out, "la      r2,_ADD3")) {
            uart_puts("  FAIL: missing call target");
            errs = errs + 1;
        }
    }

    /* Test 4: Call as expression (return value used in assignment) */
    uart_puts("--- call: expr context ---");
