            uart_puts("  FAIL: missing jal");
            errs = errs + 1;
        }
        /* After call, r0 should be stored to X's stack location */
        if (!str_find(out, "sw      r0,")) {
            uart_puts("  FAIL: missing store of return value");
            errs = errs + 1;
        }
    }

    /* Test 5: Multiple calls in sequence */
