    uart_puts("--- basic emit ---");
    emit_init();
    emit_str("hello");
    emit_nl();
    emit_line("world");
    uart_putstr("  len=");
    print_int(emit_length());
    uart_putchar(10);
    uart_putstr("  buf: ");
    uart_putstr(emit_output());

