    parse_init("PROC FOO; END;");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);
        /* Verify key parts present */
        if (!str_find(out, "_FOO:")) {
            uart_puts("  FAIL: missing _FOO label");
            errs = errs + 1;
